var query = $.input.blogTopic;
if ($.input.targetKeyword) {
  query = $.input.targetKeyword + ' ' + $.input.blogTopic;
}
return { query: query };

var results = $.steps.researchTopic.response.results || [];
var research = '';
results.forEach(function(r, i) {
  research += 'SOURCE ' + (i + 1) + ': ' + (r.title || '') + '\n';
  research += 'URL: ' + (r.url || '') + '\n';
  research += (r.text || '').slice(0, 1500) + '\n\n';
});
return { research: research, sourceCount: results.length };

var data = $.steps.compileResearch.output;
var prompt = 'You are a professional SEO content writer. Write a comprehensive, SEO-optimized blog post based on the research provided.\n\n';
prompt += 'TOPIC: ' + $.input.blogTopic + '\n';
if ($.input.targetKeyword) {
  prompt += 'TARGET KEYWORD: ' + $.input.targetKeyword + '\n';
}
prompt += 'TARGET WORD COUNT: ' + ($.input.wordCount || 1500) + '\n\n';
prompt += 'RESEARCH MATERIAL (' + data.sourceCount + ' sources):\n' + data.research + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Write a complete blog post with compelling title, meta description, and structured content\n';
prompt += '- Include H2 and H3 headings for SEO\n';
prompt += '- Naturally incorporate the target keyword 3-5 times\n';
prompt += '- Include an introduction, 4-6 main sections, and a conclusion with CTA\n';
prompt += '- Write in an engaging, authoritative tone\n';
prompt += '- Add suggested internal/external links\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "...",\n';
prompt += '  "metaDescription": "Under 160 chars",\n';
prompt += '  "content": "Full blog post in markdown",\n';
prompt += '  "wordCount": 0,\n';
prompt += '  "seoScore": "1-10",\n';
prompt += '  "suggestedTags": ["tag1"],\n';
prompt += '  "summary": "2-sentence summary for approval email"\n';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiWrite.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: $.input.blogTopic, metaDescription: '', content: raw, wordCount: 0, seoScore: 'N/A', suggestedTags: [], summary: '' }; }

var ai = $.steps.parseAI.output;
var date = new Date().toISOString().split('T')[0];
var sheetData = [{
  'Title': ai.title || '',
  'Topic': $.input.blogTopic,
  'Target Keyword': $.input.targetKeyword || '',
  'Meta Description': (ai.metaDescription || '').slice(0, 160),
  'Word Count': ai.wordCount || '',
  'SEO Score': ai.seoScore || '',
  'Tags': (ai.suggestedTags || []).join(', '),
  'Status': 'Pending Approval',
  'Content Preview': (ai.content || '').slice(0, 500),
  'Date Created': date
}];
return { sheetData: sheetData, date: date };

var ai = $.steps.parseAI.output;
var html = '<h2>Blog Post Ready for Approval</h2>';
html += '<p><strong>Title:</strong> ' + (ai.title || '') + '</p>';
html += '<p><strong>Topic:</strong> ' + $.input.blogTopic + '</p>';
html += '<p><strong>SEO Score:</strong> ' + (ai.seoScore || 'N/A') + '/10</p>';
html += '<p><strong>Word Count:</strong> ' + (ai.wordCount || 'N/A') + '</p>';
html += '<hr>';
html += '<h3>Summary</h3>';
html += '<p>' + (ai.summary || ai.metaDescription || '') + '</p>';
html += '<h3>Content Preview</h3>';
var preview = (ai.content || '').slice(0, 1500).replace(/\n/g, '<br>');
html += '<div>' + preview + '</div>';
html += '<hr>';
html += '<p><strong>Tags:</strong> ' + (ai.suggestedTags || []).join(', ') + '</p>';
html += '<p><em>Reply to this email to approve or request changes.</em></p>';
html += '<p><small>Generated with Exa Research + Claude AI via One CLI</small></p>';
var subject = 'Blog Approval: ' + (ai.title || $.input.blogTopic);
return { subject: subject, htmlBody: html.slice(0, 1900) };
